import{_ as a,o as i,c as t,a0 as o}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"ADR-0015: Agent Stigmergy Triangulation via AST Validation","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0015-agent-stigmergy-triangulation.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0015-agent-stigmergy-triangulation.md","lastUpdated":1783623176000}'),n={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0015-agent-stigmergy-triangulation.md"};function l(s,e,r,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-0015-agent-stigmergy-triangulation-via-ast-validation" tabindex="-1">ADR-0015: Agent Stigmergy Triangulation via AST Validation <a class="header-anchor" href="#adr-0015-agent-stigmergy-triangulation-via-ast-validation" aria-label="Permalink to &quot;ADR-0015: Agent Stigmergy Triangulation via AST Validation&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The stigmergic graph (T4) uses a triangulation model to validate link quality: <code>target_hash_at_creation</code> vs <code>content_hash</code> (stale detection) and <code>ast_validated</code> (structural validation). The stale detection leg was functional after populating the real target hash at link creation time. However, <code>ast_validated</code> remained permanently <code>false</code> because no code ever set it, meaning the 1.5× energy bonus for AST-validated links was never applied.</p><p>Additionally, the <code>agent_links</code> table schema was reconciled with <code>schema_v4</code> via migration 007, but the application code (<code>nexus_mcp_stigmergy.py</code>) still used <code>int</code> for <code>source_id</code>/<code>target_id</code> while the database had migrated to <code>uuid</code> columns.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li>Agents should receive energy-boosted links when their target has been structurally validated by AST parsing</li><li>Validation must be deterministic (zero LLM cost) — a simple blob_id→L1 existence check</li><li>Links must not be born stale — <code>target_hash_at_creation</code> must match the target&#39;s actual content hash</li><li>UUID types in code must match the database schema</li></ul><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><h3 id="option-1-async-ast-validation-via-enrichment-pipeline-rejected" tabindex="-1">Option 1: Async AST validation via enrichment pipeline (rejected) <a class="header-anchor" href="#option-1-async-ast-validation-via-enrichment-pipeline-rejected" aria-label="Permalink to &quot;Option 1: Async AST validation via enrichment pipeline (rejected)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Pipeline already runs periodically</li><li><strong>Cons</strong>: Links could stay unvalidated indefinitely; no feedback to the creating agent</li></ul><h3 id="option-2-deterministic-l1-lookup-at-link-creation-selected" tabindex="-1">Option 2: Deterministic L1 lookup at link creation (selected) <a class="header-anchor" href="#option-2-deterministic-l1-lookup-at-link-creation-selected" aria-label="Permalink to &quot;Option 2: Deterministic L1 lookup at link creation (selected)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Instant validation, zero LLM cost, feedback in the creation response</li><li><strong>Cons</strong>: Requires DB join at creation time</li></ul><h3 id="option-3-llm-based-semantic-validation-of-rationale-vs-target" tabindex="-1">Option 3: LLM-based semantic validation of rationale vs target <a class="header-anchor" href="#option-3-llm-based-semantic-validation-of-rationale-vs-target" aria-label="Permalink to &quot;Option 3: LLM-based semantic validation of rationale vs target&quot;">​</a></h3><ul><li><strong>Pros</strong>: Higher quality validation</li><li><strong>Cons</strong>: Costly, slow, introduces non-determinism</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ol><li><strong>Auto-validate <code>ast_validated</code> in <code>nexus_link()</code></strong>: After INSERT, check if the target abstraction&#39;s <code>blob_id</code> has any L1 (AST) entry in <code>abstractions</code>. If yes, set <code>ast_validated = true</code> and include it in the return payload.</li><li><strong>Expose <code>nexus_validate_link(link_id)</code> as an MCP tool</strong>: For manual re-validation or validation of legacy links.</li><li><strong>Fix <code>target_hash_at_creation</code></strong>: Populate with the real <code>content_hash</code> of the target at link creation time, preventing false stale penalties.</li><li><strong>Patch code to UUID</strong>: All <code>source_id</code>/<code>target_id</code>/<code>node_id</code> parameters changed from <code>int</code> to <code>str</code> in both <code>nexus_mcp_stigmergy.py</code> and <code>nexus_mcp_server.py</code>.</li></ol><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The L1 existence check is a fast, deterministic SQL join that costs &lt;1ms. It directly answers &quot;was this file successfully parsed as AST?&quot; — the exact semantic of <code>ast_validated</code>. The stale detection fix prevents the contradiction where a brand-new link immediately loses 90% energy due to <code>target_hash_at_creation = &#39;&#39;</code> not matching the real hash. Exposing a manual validation tool via MCP gives agents control over re-validation after pipeline enrichment.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>New links immediately reflect their AST validation status in the creation response</li><li>1.5× energy bonus now actually applies to validated links</li><li>No false stale penalty on fresh links</li><li>Code type signatures match the database schema</li><li>Manual re-validation available via MCP</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Links to L2-only abstractions (no L1 parent) will never auto-validate — acceptable since L2 is a semantic enrichment layer, not structural</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>None identified. The L1 join is read-only and the UPDATE is a single row.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><ul><li><code>_check_ast_validated(cur, abstraction_id)</code> does: <code>JOIN abstractions a1 ON a1.blob_id = a2.blob_id WHERE a2.id = $1 AND a1.level = 1</code></li><li><code>nexus_validate_link()</code> is exposed as an MCP tool with signature <code>(link_id: str) -&amp;gt; str</code></li><li>Migration 007 was rewritten as idempotent: uses <code>IF NOT EXISTS</code> and <code>OR REPLACE</code> for all DDL</li><li>Antigravity auth was removed from <code>opencode.json</code>; local models (Ollama) + paid API is the new auth model</li></ul><h2 id="related-decisions" tabindex="-1">Related Decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related Decisions&quot;">​</a></h2><ul><li>ADR-0007: Causalidade Topológica (Temporal Gravity Boundaries)</li><li>ADR-0009: Synesthetic Topology</li><li>Migration 007: schema_v4 reconciliation</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><code>/var/home/bruno/NEXUS/scripts/nexus_mcp_stigmergy.py</code> - nexus_link, nexus_validate_link, _check_ast_validated</li><li><code>/var/home/bruno/NEXUS/scripts/nexus_mcp_server.py</code> - MCP tool exposure</li><li><code>/var/home/bruno/NEXUS/workspace/database/migrations/007_reconcile_schema_v4.sql</code></li></ul>',32)])])}const m=a(n,[["render",l]]);export{g as __pageData,m as default};
